INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES (0, "マコトさん？\nどうかしましたか？\n何やら不穏な気配を\n感じ取ったのですが", 11, 0, 0.8, 1, 6, 129911, 6011, 6, 0);
INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES ("", "", 91, "", "", "", 6, 0, 6012, "", "");
