INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES ("", "vo_minigame_1013_top_talk_6_002", 21, "", "", 0, 6, "vo_minigame_1013", 6015, 0, "");
INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES (0, "いやいや何でもない！\nあたしは別に変なこと\n考えてないからな！\nそれより訓練だっ！", 11, 0, 0.3, 1, 6, 129811, 6016, 9, 0);
