INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES (0, "私の班のみなさんも\n変わらず訓練に励んで\nいるようですわね\n殊勝なことです", 11, 0, 0.3, 1, 7, 129911, 7006, 6, 0);
INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES ("", "", 91, "", "", "", 7, 0, 7007, "", "");
