INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES (0, "彼らが私に逆らわずに\n努力したからこそ、\n得たものもありますし\n…感謝しておきますわ", 11, 0, 0.5, 1, 7, 129911, 7016, 6, 0);
