INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES (0, "くっ、そう言われると\n悔しいな…！\nならこの行軍訓練で\n逆転してやるぜ！", 11, 0, 0.3, 1, 8, 129811, 8016, 7, 0);
